import{_ as t,o,c as a,a2 as s}from"./chunks/framework.CHeM0PsO.js";const h=JSON.parse('{"title":"RFC 0025 — Accessibility (WCAG 2.1 AA)","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0025-accessibility.md","filePath":"rfcs/0025-accessibility.md"}'),n={name:"rfcs/0025-accessibility.md"};function i(r,e,c,d,l,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="rfc-0025-—-accessibility-wcag-2-1-aa" tabindex="-1">RFC 0025 — Accessibility (WCAG 2.1 AA) <a class="header-anchor" href="#rfc-0025-—-accessibility-wcag-2-1-aa" aria-label="Permalink to &quot;RFC 0025 — Accessibility (WCAG 2.1 AA)&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> <code>packages/ui</code>, <code>docs/design-system.md</code>, <code>docs/plugin-development.md</code>, <code>eslint.config.ts</code>, SRS; builds on RFC 0001 (Dialog focus trap), RFC 0011 (Icon aria-hidden), RFC 0013 (touch targets)<br><strong>Incorporated into plan:</strong> Yes — Task 0.5.29. SRS NFR ID assigned during the implementation task.</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Establish <strong>WCAG 2.1 AA</strong> as the explicit compliance target for all platform-owned UI, add automated a11y linting to the CI pipeline, and give plugin developers a clear a11y contract so third-party plugins don&#39;t accidentally ship inaccessible experiences.</p><p>The work lands in three axes — design system contract, ESLint enforcement, and plugin developer guidance — and is delivered in one implementation task (0.5.28) after this RFC is accepted. No production behaviour changes in this RFC; it is strategy and specification.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign is positioned as a self-hosted, privacy-first workspace. That positioning actively attracts users who rely on assistive technology: screen readers, switch access, keyboard-only navigation, and display adaptations. A platform that can&#39;t be used by AT users contradicts its own principles.</p><p>The published <code>@sovereignfs/ui</code> design system is a public contract for plugin developers. Without an explicit a11y guarantee, that contract is incomplete: a plugin author using <code>&lt;Button&gt;</code> or <code>&lt;Dialog&gt;</code> can&#39;t know whether the components they ship are accessible. The ecosystem inherits any gap.</p><p>The current state has scattered a11y primitives but no formal commitment:</p><ul><li><code>packages/ui/src/components/Dialog/Dialog.tsx</code> has a full focus trap, <code>role=&quot;dialog&quot;</code>, <code>aria-modal=&quot;true&quot;</code>, Esc dismissal, and focus restoration — but this is undocumented as a contract.</li><li><code>runtime/app/(platform)/_components/AccountMenu.tsx</code> uses <code>aria-expanded</code> and Esc/click-outside — also undocumented.</li><li><code>--sv-color-focus-ring</code> exists in the token set but its use on interactive elements is not codified.</li><li>RFC 0013 sets 44px touch targets and <code>prefers-color-scheme</code> theming, but <code>prefers-reduced-motion</code> is not handled.</li><li>No linting catches new violations automatically.</li><li><code>docs/plugin-development.md</code> has no accessibility section.</li></ul><p>The gap between &quot;has some a11y&quot; and &quot;has a verified, documented, enforced a11y baseline&quot; is exactly what ships broken keyboard flows and screen-reader experiences in production.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Dialog component</strong> — <code>packages/ui/src/components/Dialog/Dialog.tsx</code>: <code>role=&quot;dialog&quot;</code>, <code>aria-modal</code>, <code>aria-label</code>, focus trap (<code>FOCUSABLE</code> selector on open), focus restoration to <code>previouslyFocused</code> on close, Esc via <code>onKeyDown</code>, close button <code>aria-label=&quot;Close&quot;</code>. The implementation is correct; the spec is absent.</li><li><strong>AccountMenu</strong> — <code>runtime/app/(platform)/_components/AccountMenu.tsx</code>: popover menu with <code>aria-expanded</code>, Esc, click-outside, keyboard-accessible trigger.</li><li><strong>Semantic tokens</strong> — <code>packages/ui/src/tokens/semantic.css</code>: <code>--sv-color-focus-ring</code> exists; no rule mandates its use on interactive elements.</li><li><strong>Icon</strong> — RFC 0011 (Task 0.5.18, unimplemented): specifies <code>aria-hidden</code> for decorative icons and <code>aria-label</code> for functional ones. This RFC depends on that convention being established.</li><li><strong>Touch targets</strong> — RFC 0013 (Task 0.5.26, unimplemented): sets <code>--sv-touch-target-min: 44px</code> and enforces it on interactive elements. The a11y audit in Task 0.5.29 should run after 0.5.25.</li><li><strong>ESLint</strong> — <code>eslint.config.ts</code> (root, flat config, Task 0.3.3): <code>typescript-eslint</code> recommended + strict, <code>eslint-config-prettier</code>. Adding <code>eslint-plugin-jsx-a11y</code> follows this pattern without structural change.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="compliance-target" tabindex="-1">Compliance target <a class="header-anchor" href="#compliance-target" aria-label="Permalink to &quot;Compliance target&quot;">​</a></h3><p><strong>WCAG 2.1 AA</strong> for all platform-owned UI (shell chrome, auth UI, Console, Launcher, Account, and all <code>packages/ui</code> components). This is the legal baseline in most jurisdictions, the standard tested by common tooling (<code>axe</code>, <code>jsx-a11y</code>), and the one most AT users cite. WCAG 2.2 AA is additive and treated as a future upgrade path, not a blocker.</p><p>The target applies to the platform. Plugin developers are <em>expected</em> to follow the plugin a11y contract (see Axis C below); <code>@sovereignfs/ui</code> components are <em>guaranteed</em> to meet it.</p><h3 id="axis-a-—-design-system-a11y-contract-packages-ui" tabindex="-1">Axis A — Design system a11y contract (<code>packages/ui</code>) <a class="header-anchor" href="#axis-a-—-design-system-a11y-contract-packages-ui" aria-label="Permalink to &quot;Axis A — Design system a11y contract (`packages/ui`)&quot;">​</a></h3><h4 id="focus-visible" tabindex="-1">Focus visible <a class="header-anchor" href="#focus-visible" aria-label="Permalink to &quot;Focus visible&quot;">​</a></h4><p>Every interactive <code>packages/ui</code> component (Button, Input, any future Select, Checkbox, etc.) exposes a <code>:focus-visible</code> outline referencing <code>--sv-color-focus-ring</code>. This is already true in practice for Button; it becomes an explicit contract. <code>docs/design-system.md</code> adds a &quot;Focus visible&quot; section documenting the token and the rule.</p><h4 id="new-semantic-tokens" tabindex="-1">New semantic tokens <a class="header-anchor" href="#new-semantic-tokens" aria-label="Permalink to &quot;New semantic tokens&quot;">​</a></h4><p>Status signals must never rely on color alone (WCAG 1.4.1). The existing semantic color set lacks error and success tones. Four tokens are added:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>--sv-color-error           background / border for error states</span></span>\n<span class="line"><span>--sv-color-error-text      text on a neutral surface indicating an error</span></span>\n<span class="line"><span>--sv-color-success         background / border for success states</span></span>\n<span class="line"><span>--sv-color-success-text    text on a neutral surface indicating success</span></span></code></pre></div><p>These always appear paired with an icon or text label — never as the sole differentiator. The v1 identity is monochrome; these are near-semantic values (error = a desaturated red-adjacent tone, success = desaturated green-adjacent) that do not break the monochrome character but satisfy color-independence. <code>@sovereignfs/ui</code> gets a <strong>minor</strong> bump for the new tokens (additive).</p><h4 id="contrast-commitment" tabindex="-1">Contrast commitment <a class="header-anchor" href="#contrast-commitment" aria-label="Permalink to &quot;Contrast commitment&quot;">​</a></h4><p>All semantic text/background pairs must meet:</p><ul><li><strong>4.5:1</strong> for body text (WCAG 1.4.3 AA)</li><li><strong>3:1</strong> for large text and UI component boundaries (WCAG 1.4.11 AA)</li></ul><p>The implementation task (0.5.28) audits the existing color pairs, adjusts any that fall short, and documents the ratios in <code>docs/design-system.md</code> as a permanent reference. Values are verified at authoring time (manual or a token test); runtime contrast is not asserted in CI for now.</p><h4 id="prefers-reduced-motion" tabindex="-1"><code>prefers-reduced-motion</code> <a class="header-anchor" href="#prefers-reduced-motion" aria-label="Permalink to &quot;`prefers-reduced-motion`&quot;">​</a></h4><p>Animated <code>packages/ui</code> components (Dialog entrance/exit, future Drawer, future Toast) suppress or reduce their transitions when <code>@media (prefers-reduced-motion: reduce)</code> is active. The existing Dialog has no CSS transition today; the RFC documents the rule so it is applied before animations are added.</p><h4 id="per-component-a11y-spec" tabindex="-1">Per-component a11y spec <a class="header-anchor" href="#per-component-a11y-spec" aria-label="Permalink to &quot;Per-component a11y spec&quot;">​</a></h4><p><code>docs/design-system.md</code> gains an a11y subsection for each component shipping in or before Task 0.5.29. Format: a small table covering role/element semantics, keyboard interactions, ARIA attributes, focus order, and any <code>aria-live</code> usage.</p><table tabindex="0"><thead><tr><th>Component</th><th>Role / element</th><th>Keyboard</th><th>ARIA</th><th>Focus order</th></tr></thead><tbody><tr><td>Button</td><td><code>&lt;button&gt;</code></td><td>Enter/Space activates</td><td><code>disabled</code> propagated</td><td>Natural DOM order</td></tr><tr><td>Input</td><td><code>&lt;input&gt;</code></td><td>Standard</td><td><code>aria-invalid</code>, <code>aria-describedby</code></td><td>Natural DOM order</td></tr><tr><td>Dialog</td><td><code>role=&quot;dialog&quot;</code></td><td>Esc closes, Tab traps</td><td><code>aria-modal</code>, <code>aria-label</code></td><td>First focusable on open</td></tr></tbody></table><p>The implementation task fills in all rows for the v1 component set.</p><h3 id="axis-b-—-eslint-a11y-linting" tabindex="-1">Axis B — ESLint a11y linting <a class="header-anchor" href="#axis-b-—-eslint-a11y-linting" aria-label="Permalink to &quot;Axis B — ESLint a11y linting&quot;">​</a></h3><p><code>eslint-plugin-jsx-a11y</code> (recommended ruleset) is added to <code>eslint.config.ts</code> and applied to all JSX/TSX files in the monorepo: <code>runtime/</code>, <code>apps/auth/</code>, <code>packages/ui/</code>, and <code>plugins/</code>. The recommended ruleset is chosen over strict because plugin authors using the starter template (RFC 0017) should not hit false-positive noise; violations from the recommended set are unambiguous errors.</p><p><code>pnpm lint</code> and the CI <code>lint</code> job enforce this from the moment the task lands. The implementation task must clean up any existing violations before enabling the rule — a red CI is not acceptable to merge on.</p><p>No new devDependency beyond the plugin. It follows the exact flat-config pattern established in Task 0.3.3.</p><h3 id="axis-c-—-plugin-developer-a11y-contract-docs-plugin-development-md" tabindex="-1">Axis C — Plugin developer a11y contract (<code>docs/plugin-development.md</code>) <a class="header-anchor" href="#axis-c-—-plugin-developer-a11y-contract-docs-plugin-development-md" aria-label="Permalink to &quot;Axis C — Plugin developer a11y contract (`docs/plugin-development.md`)&quot;">​</a></h3><p>A new <strong>&quot;Accessibility&quot;</strong> section, positioned after the existing &quot;Testing&quot; section and before any future appendices. It covers:</p><ol><li><p><strong>Semantic HTML first.</strong> Use the element that matches the role (<code>&lt;button&gt;</code> not <code>&lt;div onClick&gt;</code>; <code>&lt;nav&gt;</code>, <code>&lt;main&gt;</code>, <code>&lt;header&gt;</code> for landmarks; <code>&lt;h1&gt;</code>–<code>&lt;h6&gt;</code> hierarchy that makes sense without visual styling).</p></li><li><p><strong>Form label pairing.</strong> Every <code>&lt;input&gt;</code>, <code>&lt;select&gt;</code>, and <code>&lt;textarea&gt;</code> must have a visible <code>&lt;label&gt;</code> associated via <code>for</code>/<code>id</code>, or an <code>aria-label</code> when a visible label is impractical. Never use <code>placeholder</code> as the only label.</p></li><li><p><strong>Icon convention.</strong> Decorative icons (purely visual reinforcement of adjacent text) carry <code>aria-hidden=&quot;true&quot;</code>. Functional icons (standalone clickable or meaningful without surrounding text) carry <code>aria-label</code>. This follows the convention RFC 0011 establishes for the <code>&lt;Icon&gt;</code> component and applies equally to custom SVG usage.</p></li><li><p><strong>Color independence.</strong> Never use color as the sole way to convey status, state, or meaning (WCAG 1.4.1). Always pair a color change with an icon, text label, or pattern change. Use <code>--sv-color-error-text</code> / <code>--sv-color-success-text</code> with a companion icon.</p></li><li><p><strong>Keyboard operability.</strong> Every interactive element a mouse user can activate, a keyboard user must be able to activate. No <code>focus: none</code> on focusable elements. Tab order must follow the visual reading order. Modal dialogs use a focus trap (the <code>&lt;Dialog&gt;</code> primitive already provides this). Traps outside modals are forbidden.</p></li><li><p><strong>Custom widget ARIA patterns.</strong> When building a combobox, menu, tabs, tree, or other composite widget, follow the <a href="https://www.w3.org/WAI/ARIA/apg/" target="_blank" rel="noreferrer">WAI-ARIA Authoring Practices Guide</a> pattern for that widget. The APG patterns cover keyboard contract and required ARIA roles/properties.</p></li><li><p><strong>Live regions for async feedback.</strong> When content changes without a page reload in response to user action (search results, form submission outcome, item deletion), announce the change via an <code>aria-live</code> region (<code>polite</code> for non-urgent, <code>assertive</code> sparingly for errors). Never update only the visual presentation and leave AT users without feedback.</p></li><li><p><strong><code>prefers-reduced-motion</code>.</strong> Suppress or reduce any animation or transition your plugin introduces when the user has requested reduced motion.</p></li></ol><h3 id="srs-addition" tabindex="-1">SRS addition <a class="header-anchor" href="#srs-addition" aria-label="Permalink to &quot;SRS addition&quot;">​</a></h3><p>A new NFR (number assigned during the implementation task) is added to <code>docs/sovereign-proposal-plan-srs.md</code> §4.2 (Non-Functional Requirements):</p><blockquote><p><strong>NFR-11 — Accessibility.</strong> All platform-owned UI (shell chrome, auth UI, Console, Launcher, Account, <code>@sovereignfs/ui</code> components) shall conform to WCAG 2.1 Level AA. Plugin developers are expected to follow the accessibility contract in <code>docs/plugin-development.md</code>; <code>@sovereignfs/ui</code> components are guaranteed to satisfy it.</p></blockquote><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><p><strong>WCAG 2.2 AA from the start.</strong> WCAG 2.2 adds nine new success criteria over 2.1. Most are already satisfied by the existing shell (2.4.11 Focus Appearance, 2.5.3 Label in Name, 2.5.7 Dragging Movements). Adopting 2.1 now commits us to a well-tooled, well-understood baseline; the few 2.2 additions that require work (e.g. 2.4.12 Focus Appearance for all interactive elements) can be incorporated during the 0.5.28 audit without being blocked by the standard. The RFC is written to be 2.2-compatible.</p><p><strong>Axe-core / Playwright a11y automation in CI.</strong> End-to-end a11y assertions (e.g. <code>@axe-core/playwright</code> in the e2e tier) would catch rendered violations that static linting misses. This is the right long-term posture but heavyweight for Task 0.5.29 alongside the audit and documentation work. Deferred to a follow-up or the e2e tier when RFC 0019&#39;s test infrastructure is in place.</p><p><strong>Linting only — no design-system spec or plugin guidance.</strong> Linting catches authoring errors (missing labels, wrong roles) but does not establish a contract for component consumers or plugin authors. The published <code>@sovereignfs/ui</code> package needs documented behaviour, not just clean lint output, before v1.</p><p><strong>Post-v1.</strong> The design system is a public contract at v1.0; an undocumented, unlinted a11y posture is not a v1-quality contract. Deferring would mean shipping a published package that makes no guarantees about the accessibility of the components it provides.</p><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><p><strong>Contrast automation.</strong> Should semantic color token contrast ratios be verified in a Vitest test (computed at build time against known values) or left as a manual authoring commitment documented in <code>docs/design-system.md</code>? A test is more reliable but requires tooling for color-pair lookup.</p></li><li><p><strong>jsx-a11y recommended vs strict.</strong> The recommended ruleset is unambiguous but misses some nuance that strict catches. Should the platform packages (<code>packages/ui</code>, <code>runtime/</code>, <code>apps/auth/</code>) use strict while plugins (which use the starter template) get recommended? Or one ruleset everywhere for consistency?</p></li><li><p><strong><code>prefers-contrast: more</code> (high-contrast mode).</strong> Should the Task 0.5.29 scope include a <code>prefers-contrast</code> media query layer on the semantic token set, or is that deferred as a follow-up?</p></li><li><p><strong>APCA for dark mode.</strong> The WCAG relative-luminance contrast formula is known to be inaccurate for small text on dark backgrounds. Should the dark-mode color pairs target APCA (Advanced Perceptual Contrast Algorithm) ratios alongside WCAG ratios as an advisory metric?</p></li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ul><li><strong>This RFC</strong> lands in <code>docs/rfcs/</code> as a Draft. No code changes. Reviewed and either accepted or iterated on before the implementation task begins.</li><li><strong>Task 0.5.29</strong> implements the three axes: audit + fix shell/chrome/auth UI against WCAG 2.1 AA, add <code>eslint-plugin-jsx-a11y</code>, add semantic tokens, write component a11y specs in <code>docs/design-system.md</code>, write the &quot;Accessibility&quot; section in <code>docs/plugin-development.md</code>, add NFR-11 to the SRS.</li><li><strong>Semver:</strong> <code>@sovereignfs/ui</code> <strong>minor</strong> bump for the four new tokens. No breaking changes. No <code>@sovereignfs/sdk</code> change.</li><li><strong>Dependencies:</strong> Task 0.5.18 (Icon <code>aria-hidden</code>/<code>aria-label</code> convention should be established before the a11y spec references it); Task 0.5.26 (touch targets in place before the audit runs).</li></ul><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>June 2026</td><td>Initial draft</td></tr></tbody></table>',56)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
